mapper.update:
UPDATE know_posts SET update_time = NOW()
, title = #{title}
, tag_id = #{tagId}
, tags = #{tags}
, img_urls = #{imgUrls}
, visible = #{visible}
, is_top = #{isTop}
, description = #{description}
WHERE id = #{id} AND creator_id = #{creatorId}

mapper.select:
SELECT p.*, u.avatar AS author_avatar, u.nickname AS author_nickname, u.tags_json AS author_tag_json
FROM know_posts p LEFT JOIN users u ON p.creator_id = u.id
WHERE p.id = #{id}
